import boto3

def publish_notification(event, context):
    sns = boto3.client('sns')
    
    message = event['message']
    topic_arn = event['topic_arn']
    notification_type = event.get('type', 'info')

    if notification_type == 'info':
        sns.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject='INFO notification')

    elif notification_type == 'warning':
        sns.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject='WARNING notification')

    elif notification_type == 'error':
        sns.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject='ERROR notification') 

    else:
        sns.publish(
            TopicArn=topic_arn,
            Message=message,
            Subject='GENERAL notification')